exercises.solution_code:
#include <iostream>

int main()
{
    long long value{};
    std::cin >> value;

    bool fits16 { value >= -32768LL && value <= 32767LL };
    bool fits32 { value >= -2147483648LL && value <= 2147483647LL };

    long long square = value * value;

    std::cout << "Value: " << value << '\n';
    std::cout << std::boolalpha;
    std::cout << "Fits in 16-bit: " << fits16 << '\n';
    std::cout << "Fits in 32-bit: " << fits32 << '\n';
    std::cout << "Square: " << square << '\n';

    return 0;
}

