exercises.solution_code:
#include <iostream>
#include <iomanip>

int main()
{
    long long a{}, b{}, c{};
    std::cin >> a >> b >> c;

    long long sum = a + b + c;
    double avg = static_cast<double>(sum) / 3.0;
    long long product = a * b;

    std::cout << "Sum: " << sum << '\n';
    std::cout << std::fixed << std::setprecision(2);
    std::cout << "Average: " << avg << '\n';
    std::cout << "Product of first two: " << product << '\n';

    return 0;
}
